void merge_sort(std::vector<int> arr) {}

int int_len(int num) {
    int count = 0;
    while (num != 0) {
        num = num / 10;
        count++;
    }
    return count;
}

int get_prefix_len_math(int n1, int n2, int n1_len, int n2_len){
    int prefix_len = 0;
    int loop_n = std::min(n1_len, n2_len);
    while(loop_n-->0){
        int msb_n1 = n1/(int)pow(10,--n1_len) % 10;
        int msb_n2 = n2/(int)pow(10,--n2_len) % 10;
        if(msb_n1 == msb_n2){
            prefix_len++;
        }
        else{
            break;
        }
    }
    return prefix_len;
};

int get_prefix_len_math_prepow(int n1, int n2, int n1_len, int n2_len){
    static const int pow10[] = {1, 10, 100, 1000, 10000, 100000, 
                                 1000000, 10000000, 100000000, 1000000000};
    int prefix_len = 0;
    int loop_n = std::min(n1_len, n2_len);
    int t1 = n1_len, t2 = n2_len;
    
    while(loop_n-- > 0){
        if(((n1 / pow10[--t1]) % 10) == ((n2 / pow10[--t2]) % 10))
            prefix_len++;
        else
            break;
    }
    return prefix_len;
}

int get_prefix_len_div(int n1, int n2) {
    // Make them same length by dividing the larger one
    while(n1 > 0 && n2 > 0) {
        if(n1 == n2) {
            // Count digits of n1
            int len = 0;
            while(n1 > 0) { n1 /= 10; len++; }
            return len;
        }
        if(n1 > n2) n1 /= 10;
        else n2 /= 10;
    }
    return 0;
}

int get_prefix_len_str(int n1, int n2) {
    std::string s1 = std::to_string(n1);
    std::string s2 = std::to_string(n2);
    
    int prefix_len = 0;
    int min_len = std::min(s1.length(), s2.length());
    
    for(int i = 0; i < min_len; i++) {
        if(s1[i] == s2[i]) prefix_len++;
        else break;
    }
    return prefix_len;
}

int longestCommonPrefix(std::vector<int> &arr1, std::vector<int> &arr2) {
    int prefix = 0, prefix_len = 0, curr_prefix_len = 0;
    for (int n1 : arr1) {
        int n1_len = int_len(n1);
        if (n1_len <= prefix_len) {
            continue;;
        }
        for (int n2 : arr2) {
            int n2_len = int_len(n2);
            if (n2_len <= prefix_len) {
                continue;
            }
            // curr_prefix_len = get_prefix_len_math(n1, n2, n1_len, n2_len);
            curr_prefix_len = get_prefix_len_math_prepow(n1, n2, n1_len, n2_len);
            // curr_prefix_len = get_prefix_len_div(n1, n2);
            // curr_prefix_len = get_prefix_len_str(n1, n2);
            // printf("{n1, n2} : {%d, %d}\n", n1, n2);
            // printf("prefix_len, curr_prefix_len : %d, %d\n", prefix_len, curr_prefix_len);
            if(curr_prefix_len > prefix_len){
                prefix_len = curr_prefix_len;
            }

        }
    }
    return prefix_len;
}

